\section{Producer instance for \texttt{IsHModuleHomFinite} on the curve sheaf (iter-046)}
\label{sec:IsHModuleHomFinite_producer}

Iter-046 collapses the originally-multi-iteration step (1) (linearised constant-sheaf / global-sections adjunction \lstinline{LinearEquiv}) plus the iter-047-planned producer-instance assembly into a single iteration via three observations:
\begin{itemize}
  \item Mathlib's \lstinline{Adjunction.homAddEquiv} (\lstinline{Mathlib/CategoryTheory/Adjunction/Additive.lean}) lifts the bare $\mathtt{homEquiv}$ to an additive equivalence under $F.\mathtt{Additive}$. The further upgrade to $\LinearEquiv\,k$ (under $F.\mathtt{Linear}\,k$) is a one-liner via $(\mathtt{adj.homEquiv}).\mathtt{injective} + \mathtt{simp}\,[\mathtt{adj.homEquiv\_unit}]$, mirroring Mathlib's \lstinline{left_adjoint_additive}. This is project-local Mathlib gap-fills \lstinline{Adjunction.left_adjoint_linear} + \lstinline{Adjunction.right_adjoint_linear} + \lstinline{Adjunction.homLinearEquiv}.
  \item The $\Functor.\Linear\,k$ propagation chain — $\mathtt{Functor.const}$ Linear (one-liner), $\mathtt{presheafToSheaf}$ Linear (via \lstinline{sheafificationAdjunction.left_adjoint_linear}), $\mathtt{constantSheaf}$ Linear (via composition), $\Sheaf.\Gamma$ Linear (via \lstinline{constantSheafΓAdj.right_adjoint_linear}) — is mechanical.
  \item The Hom-from-$k$ upgrade $(\ModuleCat.\mathrm{of}\,k\,k \to M) \equivl{k} M$ for $M : \ModuleCat\,k$ is a Mathlib-already-existing one-liner via \lstinline{ModuleCat.homLinearEquiv} composed with \lstinline{LinearMap.ringLmapEquivSelf}.
\end{itemize}

The producer instance combines all three with iter-045's evaluation iso to land $\Module.\mathrm{Finite}\,k\,((\mathtt{constantSheaf}).\mathtt{obj}\,(\ModuleCat.\mathrm{of}\,k\,k) \to \toModuleKSheaf\,C)$ from the iter-044 geometric Stein input. Once registered as a typeclass instance, iter-043's curve consumer \lstinline{module_finite_HModule_zero_of_isHModuleHomFinite_curve} fires automatically on $\Module.\mathrm{Finite}\,k\,(\HModule\,k\,(\toModuleKSheaf\,C)\,0)$ queries — closing the H$^0$ side of the genus-finrank Module.Finite ladder.

\subsection{General Mathlib gap-fills}

\begin{lemma}\leanok
[Linear lifting of \texttt{left\_adjoint\_additive}]
  \label{lemma:Adjunction_left_adjoint_linear}
  \lean{CategoryTheory.Adjunction.left_adjoint_linear}
  Let $F : \mathcal{C} \to \mathcal{D}$ be a functor between $R$-linear preadditive categories with right adjoint $G$. If $G$ is $R$-linear (and additive), then $F$ is $R$-linear.
\end{lemma}

\begin{proof}
  \leanok
  Mirrors Mathlib's \lstinline{left_adjoint_additive}. By $\mathtt{homEquiv}$-injectivity, $F.\mathtt{map}\,(r \cdot f) = r \cdot F.\mathtt{map}\,f$ reduces to an equality on the right side of the adjunction, where $\mathtt{simp}\,[\mathtt{adj.homEquiv\_unit}]$ rewrites both sides via unit naturality and the default simp lemmas \lstinline{Linear.smul_comp} and \lstinline{Linear.comp_smul}.
\end{proof}

\begin{lemma}\leanok
[Right-adjoint version]
  \label{lemma:Adjunction_right_adjoint_linear}
  \lean{CategoryTheory.Adjunction.right_adjoint_linear}
  Dual of Lemma~\ref{lemma:Adjunction_left_adjoint_linear}: if $F$ is $R$-linear (and additive), then $G$ is $R$-linear.
\end{lemma}

\begin{proof}
  \leanok
  Same proof shape, using $\mathtt{adj.homEquiv\_counit}$ in place of $\mathtt{adj.homEquiv\_unit}$.
\end{proof}

\begin{theorem}\leanok
[Linear hom-equivalence from an adjunction]
  \label{def:Adjunction_homLinearEquiv}
  \lean{CategoryTheory.Adjunction.homLinearEquiv}
  \uses{lemma:Adjunction_left_adjoint_linear}
  Let $\mathtt{adj} : F \dashv G$ between $R$-linear preadditive categories with $F.\mathtt{Additive}$, $G.\mathtt{Additive}$, $G.\mathtt{Linear}\,R$. Then for all objects $X$ and $Y$, the additive equivalence $\mathtt{adj.homAddEquiv}\,X\,Y$ upgrades to a $\LinearEquiv$ over $R$:
  \[
    (F.\mathtt{obj}\,X \to Y) \;\equivl{R}\; (X \to G.\mathtt{obj}\,Y).
  \]
\end{theorem}

\begin{proof}
  \leanok
  Build the $\LinearEquiv$ structure by overriding the \lstinline{map_smul'} field of \lstinline{adj.homAddEquiv}: the $\mathtt{change}$ tactic exposes the underlying $\mathtt{homEquiv}$ form, after which $\mathtt{simp}\,[\mathtt{adj.homEquiv\_unit}]$ closes via the same naturality argument as Lemma~\ref{lemma:Adjunction_left_adjoint_linear}. The \lstinline{haveI} line that establishes $F.\mathtt{Linear}\,R$ via Lemma~\ref{lemma:Adjunction_left_adjoint_linear} is load-bearing.
\end{proof}

\subsection{Project-local applied bridges and the producer instance}

\begin{theorem}\leanok
[Constant-sheaf / global-sections $\LinearEquiv$]
  \label{def:Scheme_constantSheafGammaHom_linearEquiv}
  \lean{AlgebraicGeometry.Scheme.constantSheafGammaHom_linearEquiv}
  \uses{def:Adjunction_homLinearEquiv}
  Let $k$ be a field, $\mathcal{C}$ a small category, $J$ a Grothendieck topology on $\mathcal{C}$ with sheafification valued in $\ModuleCat\,k$, and global-sections functor in scope. For any $X : \ModuleCat\,k$ and $F : \Sheaf\,J\,(\ModuleCat\,k)$:
  \[
    ((\mathtt{constantSheaf}\,J\,\_).\mathtt{obj}\,X \to F) \;\equivl{k}\; (X \to (\Sheaf.\Gamma\,J\,\_).\mathtt{obj}\,F).
  \]
\end{theorem}

\begin{proof}
  \leanok
  Five \lstinline{haveI} lines build the typeclass scaffolding: $\mathtt{presheafToSheaf}$ Linear via \lstinline{sheafificationAdjunction.left_adjoint_linear}, $\mathtt{constantSheaf}$ Additive + Linear via composition with $\mathtt{Functor.const}$, and $\Sheaf.\Gamma$ Additive + Linear via \lstinline{constantSheafΓAdj.right_adjoint_*} along Lemma~\ref{lemma:Adjunction_right_adjoint_linear}. The body invokes Theorem~\ref{def:Adjunction_homLinearEquiv} on Mathlib's adjunction \lstinline{constantSheafΓAdj}.
\end{proof}

\begin{theorem}\leanok
[Hom-from-$k$ upgrade]
  \label{def:Scheme_homFromOne_linearEquiv}
  \lean{AlgebraicGeometry.Scheme.homFromOne_linearEquiv}
  For any field $k$ and $M : \ModuleCat\,k$:
  \[
    (\ModuleCat.\mathrm{of}\,k\,k \to M) \;\equivl{k}\; M.
  \]
\end{theorem}

\begin{proof}
  \leanok
  Direct one-liner combining \lstinline{ModuleCat.homLinearEquiv} (Mathlib's $\LinearEquiv$-version of the underlying-LinearMap correspondence) with \lstinline{LinearMap.ringLmapEquivSelf} (the standard $(R \to_{R} M) \equivl{S} M$ evaluation at $1$).
\end{proof}

\begin{theorem}\leanok
[Producer instance for \texttt{IsHModuleHomFinite}]
  \label{inst:Scheme_instIsHModuleHomFinite_toModuleKSheaf}
  \lean{AlgebraicGeometry.Scheme.instIsHModuleHomFinite_toModuleKSheaf}
  \uses{def:Scheme_constantSheafGammaHom_linearEquiv, def:Scheme_homFromOne_linearEquiv, thm:Scheme_module_finite_gammaObj_of_isProper}
